codeSnippets.go:
type node struct {
	Value int
	Next  *node
	Prev  *node
}

type Deque struct {
	Front *node
	Rear  *node
}

func (d *Deque) PushFront(value int) {
	n := &node{Value: value, Next: d.Front}
	if d.Front != nil {
		d.Front.Prev = n
	} else {
		d.Rear = n
	}
	d.Front = n
}

func (d *Deque) PushBack(value int) {
	n := &node{Value: value, Prev: d.Rear}
	if d.Rear != nil {
		d.Rear.Next = n
	} else {
		d.Front = n
	}
	d.Rear = n
}

codeSnippets.javascript:
class Deque {
  constructor() {
    this.data = [];
  }

  pushFront(value) { this.data.unshift(value); }
  pushBack(value)  { this.data.push(value); }
  popFront()       { return this.data.shift(); }
  popBack()        { return this.data.pop(); }
  peekFront()      { return this.data[0]; }
  peekBack()       { return this.data[this.data.length - 1]; }
}
